import {
    flexRender,
    getCoreRowModel,
    getSortedRowModel,
    useReactTable,
    createColumnHelper,
    SortingState,
    VisibilityState,
} from "@tanstack/react-table";

import { formatCurrency } from "@/lib/utils";
import { ActivityItem } from "./types";
import {
    ArrowDownLeft,
    ArrowUpRight,
    ArrowDown,
    ArrowUp,
    Settings2,
    Loader2,
    Search,
    Filter,
    X,
    Calendar,
    ChevronRight,
} from "lucide-react";
import { useState } from "react";

interface ActivityListProps {
    data: ActivityItem[];
    selectedItem: ActivityItem | null;
    onItemClick: (item: ActivityItem) => void;
    onLoadMoreButtonClick: () => void;
    hasMore: boolean;
    isLoadingMore: boolean;
    isFiltering: boolean;
    onApplyFilter: (start?: string, end?: string) => void;
    onClearFilter: () => void;
}

const columnHelper = createColumnHelper<ActivityItem>();

const columns = [
    columnHelper.display({
        id: "index",
        header: () => "No.#",
        size: 20,
        cell: (info) => (
            <div className="text-center text-xs font-medium text-gray-400">
                {info.row.index + 1}
            </div>
        ),
    }),
    columnHelper.accessor("date", {
        header: "Date",
        size: 100,
        cell: (info) => (
            <span className="text-xs text-gray-500">
                {new Date(info.getValue()).toLocaleDateString("en-US", {
                    month: "short",
                    day: "numeric",
                    year: "2-digit",
                })}
            </span>
        ),
    }),
    columnHelper.accessor("name", {
        header: "Details",
        size: 250,
        cell: (info) => {
            const item = info.row.original;
            return (
                <div className="flex items-center gap-3">
                    <div
                        className={`shrink-0 rounded-full p-1.5 ${item.isIncome ? "bg-green-100" : "bg-red-50"}`}
                    >
                        {item.isIncome ? (
                            <ArrowDownLeft className="h-3 w-3 text-green-600" />
                        ) : (
                            <ArrowUpRight className="h-3 w-3 text-red-600" />
                        )}
                    </div>
                    <div className="flex flex-col overflow-hidden">
                        <span className="truncate text-sm font-medium text-gray-900">
                            {info.getValue()}
                        </span>
                        <span className="text-xs text-gray-500">
                            {item.type}
                        </span>
                    </div>
                </div>
            );
        },
    }),
    columnHelper.accessor("currency", {
        header: "Currency",
        size: 100,
        cell: (info) => (
            <span className="text-sm text-gray-500">{info.getValue()}</span>
        ),
    }),
    columnHelper.accessor("groupName", {
        header: "Group",
        size: 140,
        cell: (info) => (
            <span className="text-sm text-gray-500">
                {info.getValue() || "-"}
            </span>
        ),
    }),
    columnHelper.accessor("hasReceipt", {
        header: "Receipt",
        size: 100,
        cell: (info) => (
            <span className="text-sm text-gray-500">
                {info.getValue() ? "Yes" : "No"}
            </span>
        ),
    }),
    columnHelper.accessor("splitCount", {
        header: "Split",
        size: 100,
        cell: (info) => (
            <span className="text-sm text-gray-500">
                {info.getValue() > 0 ? info.getValue() : "-"}
            </span>
        ),
    }),
    columnHelper.accessor("amount", {
        header: () => <div className="text-right">Amount</div>,
        size: 120,
        cell: (info) => {
            const item = info.row.original;
            return (
                <div
                    className={`text-right text-sm font-semibold ${item.isIncome ? "text-green-600" : "text-red-500"}`}
                >
                    {formatCurrency((item.isIncome ? 1 : -1) * info.getValue())}
                </div>
            );
        },
        sortingFn: (a, b) => {
            const amountA = a.original.amount * (a.original.isIncome ? 1 : -1);
            const amountB = b.original.amount * (b.original.isIncome ? 1 : -1);
            return amountA > amountB ? 1 : amountA < amountB ? -1 : 0;
        },
    }),
];

export function ActivityList({
    data,
    selectedItem,
    onItemClick,
    onLoadMoreButtonClick,
    hasMore,
    isLoadingMore,
    isFiltering,
    onApplyFilter,
    onClearFilter,
}: ActivityListProps) {
    const [isScrolled, setIsScrolled] = useState(false);
    const [sorting, setSorting] = useState<SortingState>([]);

    const [columnVisibility, setColumnVisibility] = useState<VisibilityState>({
        index: false,
        currency: false,
        hasReceipt: false,
        splitCount: false,
    });
    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [isResizingEnabled, setIsResizingEnabled] = useState(true);

    const [filterMode, setFilterMode] = useState<"none" | "month" | "range">(
        "none",
    );
    const [isEditing, setIsEditing] = useState(false);
    const [monthValue, setMonthValue] = useState("");
    const [startDate, setStartDate] = useState("");
    const [endDate, setEndDate] = useState("");

    const table = useReactTable({
        data,
        columns,
        state: {
            sorting,
            columnVisibility,
        },
        onSortingChange: setSorting,
        onColumnVisibilityChange: setColumnVisibility,
        getCoreRowModel: getCoreRowModel(),
        getSortedRowModel: getSortedRowModel(),
        columnResizeMode: "onChange",
    });

    const handleScroll = (e: React.UIEvent<HTMLDivElement>) => {
        setIsScrolled(e.currentTarget.scrollTop > 0);
    };

    const toggleResizing = (enabled: boolean) => {
        setIsResizingEnabled(enabled);
        if (!enabled) {
            table.resetColumnSizing();
        }
    };

    // --- NEW: Calculate dates before sending to parent ---
    function handleApply() {
        let calculatedStart: string | undefined = undefined;
        let calculatedEnd: string | undefined = undefined;

        if (filterMode === "month" && monthValue) {
            const [year, month] = monthValue.split("-");
            calculatedStart = new Date(
                parseInt(year),
                parseInt(month) - 1,
                1,
            ).toISOString();
            calculatedEnd = new Date(
                parseInt(year),
                parseInt(month),
                0,
                23,
                59,
                59,
                999,
            ).toISOString();
        } else if (filterMode === "range" && startDate && endDate) {
            calculatedStart = new Date(
                `${startDate}T00:00:00.000`,
            ).toISOString();
            calculatedEnd = new Date(`${endDate}T23:59:59.999`).toISOString();
        }

        setIsEditing(false);
        onApplyFilter(calculatedStart, calculatedEnd);
    }

    function handleClear() {
        setMonthValue("");
        setStartDate("");
        setEndDate("");
        setFilterMode("none");
        setIsEditing(false);
        onClearFilter();
    }

    return (
        <div className="flex h-full flex-col">
            {/* UNIFIED TOOLBAR */}
            <div className="flex shrink-0 items-center justify-between border-b border-gray-100 bg-white px-5 py-3">
                <div className="flex flex-1 items-center gap-2">
                    {filterMode === "none" ? (
                        <>
                            <button
                                onClick={() => {
                                    setFilterMode("month");
                                    setIsEditing(true);
                                }}
                                className="flex items-center gap-2 rounded-full border border-gray-200 bg-white px-4 py-1.5 text-sm font-medium text-gray-600 transition-all hover:border-orange-200 hover:bg-orange-50 hover:text-orange-600"
                            >
                                <Calendar className="h-4 w-4" />
                                Month
                            </button>
                            <button
                                onClick={() => {
                                    setFilterMode("range");
                                    setIsEditing(true);
                                }}
                                className="flex items-center gap-2 rounded-full border border-gray-200 bg-white px-4 py-1.5 text-sm font-medium text-gray-600 transition-all hover:border-orange-200 hover:bg-orange-50 hover:text-orange-600"
                            >
                                <Filter className="h-4 w-4" />
                                Date Range
                            </button>
                        </>
                    ) : filterMode === "month" ? (
                        isEditing || !isFiltering ? (
                            <div className="animate-in fade-in zoom-in-95 flex items-center gap-2 rounded-full border border-orange-200 bg-orange-50/30 p-1 pl-4 duration-200">
                                <span className="text-xs font-semibold tracking-wider text-orange-600 uppercase">
                                    Month
                                </span>
                                <input
                                    type="month"
                                    value={monthValue}
                                    onChange={(e) =>
                                        setMonthValue(e.target.value)
                                    }
                                    className="bg-transparent text-sm font-medium text-gray-900 [color-scheme:light] outline-none"
                                />
                                <div className="flex items-center gap-1 pl-2">
                                    <button
                                        onClick={handleApply}
                                        disabled={!monthValue}
                                        className="rounded-full bg-orange-600 px-3 py-1 text-xs font-bold text-white hover:bg-orange-700 disabled:opacity-50"
                                    >
                                        Apply
                                    </button>
                                    <button
                                        onClick={() => {
                                            if (!isFiltering)
                                                setFilterMode("none");
                                            setIsEditing(false);
                                        }}
                                        className="rounded-full p-1 text-gray-400 hover:bg-gray-100 hover:text-gray-600"
                                    >
                                        <X className="h-4 w-4" />
                                    </button>
                                </div>
                            </div>
                        ) : (
                            <button
                                onClick={() => setIsEditing(true)}
                                className="flex items-center gap-2 rounded-full border border-orange-200 bg-orange-50 px-4 py-1.5 text-sm font-semibold text-orange-700 transition-all hover:bg-orange-100"
                            >
                                <Calendar className="h-4 w-4" />
                                {new Date(
                                    monthValue + "-01",
                                ).toLocaleDateString("en-US", {
                                    month: "short",
                                    year: "numeric",
                                })}
                                <div
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        handleClear();
                                    }}
                                    className="ml-1 rounded-full p-0.5 hover:bg-orange-200"
                                >
                                    <X className="h-3.5 w-3.5" />
                                </div>
                            </button>
                        )
                    ) : isEditing || !isFiltering ? (
                        <div className="animate-in fade-in zoom-in-95 flex items-center gap-2 rounded-full border border-orange-200 bg-orange-50/30 p-1 pl-4 duration-200">
                            <span className="text-xs font-semibold tracking-wider text-orange-600 uppercase">
                                Range
                            </span>
                            <div className="flex items-center gap-2">
                                <input
                                    type="date"
                                    value={startDate}
                                    onChange={(e) =>
                                        setStartDate(e.target.value)
                                    }
                                    className="bg-transparent text-sm font-medium text-gray-900 [color-scheme:light] outline-none"
                                />
                                <ChevronRight className="h-3 w-3 text-gray-400" />
                                <input
                                    type="date"
                                    value={endDate}
                                    onChange={(e) => setEndDate(e.target.value)}
                                    className="bg-transparent text-sm font-medium text-gray-900 [color-scheme:light] outline-none"
                                />
                            </div>
                            <div className="flex items-center gap-1 pl-2">
                                <button
                                    onClick={handleApply}
                                    disabled={!startDate || !endDate}
                                    className="rounded-full bg-orange-600 px-3 py-1 text-xs font-bold text-white hover:bg-orange-700 disabled:opacity-50"
                                >
                                    Apply
                                </button>
                                <button
                                    onClick={() => {
                                        if (!isFiltering) setFilterMode("none");
                                        setIsEditing(false);
                                    }}
                                    className="rounded-full p-1 text-gray-400 hover:bg-gray-100 hover:text-gray-600"
                                >
                                    <X className="h-4 w-4" />
                                </button>
                            </div>
                        </div>
                    ) : (
                        <button
                            onClick={() => setIsEditing(true)}
                            className="flex items-center gap-2 rounded-full border border-orange-200 bg-orange-50 px-4 py-1.5 text-sm font-semibold text-orange-700 transition-all hover:bg-orange-100"
                        >
                            <Filter className="h-4 w-4" />
                            {new Date(startDate).toLocaleDateString("en-US", {
                                month: "short",
                                day: "numeric",
                            })}{" "}
                            -{" "}
                            {new Date(endDate).toLocaleDateString("en-US", {
                                month: "short",
                                day: "numeric",
                            })}
                            <div
                                onClick={(e) => {
                                    e.stopPropagation();
                                    handleClear();
                                }}
                                className="ml-1 rounded-full p-0.5 hover:bg-orange-200"
                            >
                                <X className="h-3.5 w-3.5" />
                            </div>
                        </button>
                    )}
                </div>

                <div className="relative">
                    <button
                        onClick={() => setIsMenuOpen(!isMenuOpen)}
                        className="flex items-center gap-2 rounded-full border border-gray-200 bg-white px-4 py-1.5 text-sm font-medium text-gray-600 transition-all hover:border-gray-300 hover:bg-gray-50 hover:text-gray-900"
                    >
                        <Settings2 className="h-4 w-4" />
                        Columns
                    </button>

                    {isMenuOpen && (
                        <div className="animate-in fade-in slide-in-from-top-2 absolute top-10 right-0 z-50 w-56 rounded-xl border border-gray-200 bg-white p-2 shadow-xl duration-200">
                            <div className="mb-2 px-2 text-xs font-bold tracking-widest text-gray-400 uppercase">
                                View Options
                            </div>
                            <label className="mb-2 flex cursor-pointer items-center gap-2 rounded-lg px-2 py-2 hover:bg-gray-50">
                                <input
                                    type="checkbox"
                                    checked={isResizingEnabled}
                                    onChange={(e) =>
                                        toggleResizing(e.target.checked)
                                    }
                                    className="rounded border-gray-300 text-orange-500 focus:ring-orange-500"
                                />
                                <span className="text-sm font-semibold text-gray-700">
                                    Resizable Columns
                                </span>
                            </label>

                            <div className="my-2 border-t border-gray-100" />

                            <div className="mb-2 px-2 text-xs font-bold tracking-widest text-gray-400 uppercase">
                                Visible Columns
                            </div>
                            <div className="max-h-48 overflow-y-auto">
                                {table.getAllLeafColumns().map((column) => {
                                    return (
                                        <label
                                            key={column.id}
                                            className="flex cursor-pointer items-center gap-2 rounded-lg px-2 py-1.5 hover:bg-gray-50"
                                        >
                                            <input
                                                type="checkbox"
                                                checked={column.getIsVisible()}
                                                onChange={column.getToggleVisibilityHandler()}
                                                className="rounded border-gray-300 text-orange-500 focus:ring-orange-500"
                                            />
                                            <span className="text-sm text-gray-600 capitalize">
                                                {column.id}
                                            </span>
                                        </label>
                                    );
                                })}
                            </div>
                        </div>
                    )}
                </div>
            </div>

            <div
                className="relative max-h-full flex-1 overflow-y-auto px-2 pt-2"
                onScroll={handleScroll}
            >
                {/* --- NEW: SPINNER DURING FILTER FETCH --- */}
                {isFiltering ? (
                    <div className="flex h-full w-full items-center justify-center">
                        <Loader2 className="h-8 w-8 animate-spin text-orange-500" />
                    </div>
                ) : (
                    <>
                        <table
                            className={`w-full border-separate text-left ${isResizingEnabled ? "table-fixed" : "table-auto"}`}
                            style={{ borderSpacing: "0 6px" }}
                        >
                            <thead
                                className={`sticky top-0 z-10 bg-white/95 backdrop-blur-sm transition-shadow duration-200 ${isScrolled ? "shadow-md" : "shadow-none"}`}
                            >
                                {table.getHeaderGroups().map((headerGroup) => (
                                    <tr key={headerGroup.id}>
                                        {headerGroup.headers.map((header) => (
                                            <th
                                                key={header.id}
                                                style={
                                                    isResizingEnabled
                                                        ? {
                                                              width: header.getSize(),
                                                          }
                                                        : {}
                                                }
                                                className="group relative bg-gray-50/80 px-4 py-3 text-xs font-medium tracking-wider text-gray-500 uppercase select-none"
                                            >
                                                {header.isPlaceholder ? null : (
                                                    <div
                                                        className={`flex items-center gap-1 ${header.column.getCanSort() ? "cursor-pointer hover:text-gray-900" : ""}`}
                                                        onClick={header.column.getToggleSortingHandler()}
                                                    >
                                                        {flexRender(
                                                            header.column
                                                                .columnDef
                                                                .header,
                                                            header.getContext(),
                                                        )}
                                                        {{
                                                            asc: (
                                                                <ArrowUp className="h-3 w-3" />
                                                            ),
                                                            desc: (
                                                                <ArrowDown className="h-3 w-3" />
                                                            ),
                                                        }[
                                                            header.column.getIsSorted() as string
                                                        ] ?? null}
                                                    </div>
                                                )}

                                                {isResizingEnabled && (
                                                    <div
                                                        onMouseDown={header.getResizeHandler()}
                                                        onTouchStart={header.getResizeHandler()}
                                                        className={`absolute top-0 right-0 h-full w-1.5 cursor-col-resize rounded-2xl hover:bg-orange-400/50 ${
                                                            header.column.getIsResizing()
                                                                ? "bg-orange-500"
                                                                : ""
                                                        }`}
                                                    />
                                                )}
                                            </th>
                                        ))}
                                    </tr>
                                ))}
                            </thead>

                            <tbody>
                                {table.getRowModel().rows.map((row) => {
                                    const item = row.original;
                                    const isSelected =
                                        selectedItem?.id === item.id;
                                    const cells = row.getVisibleCells();

                                    return (
                                        <tr
                                            key={row.id}
                                            onClick={() => onItemClick(item)}
                                            className="group cursor-pointer"
                                        >
                                            {cells.map((cell, index) => {
                                                const isFirst = index === 0;
                                                const isLast =
                                                    index === cells.length - 1;

                                                return (
                                                    <td
                                                        key={cell.id}
                                                        style={
                                                            isResizingEnabled
                                                                ? {
                                                                      width: cell.column.getSize(),
                                                                  }
                                                                : {}
                                                        }
                                                        className={`px-4 py-3 whitespace-nowrap transition-colors duration-300 ${
                                                            isSelected
                                                                ? "border-y-4 border-dashed border-orange-400 bg-orange-100"
                                                                : "border-y-4 border-solid border-transparent bg-white shadow-sm group-hover:bg-blue-50 group-hover:shadow-md"
                                                        } ${isFirst ? (isSelected ? "rounded-l-2xl border-l-4" : "rounded-l-2xl border-l-4 border-transparent") : ""} ${isLast ? (isSelected ? "rounded-r-2xl border-r-4" : "rounded-r-2xl border-r-4 border-transparent") : ""}`}
                                                    >
                                                        {flexRender(
                                                            cell.column
                                                                .columnDef.cell,
                                                            cell.getContext(),
                                                        )}
                                                    </td>
                                                );
                                            })}
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>

                        {/* Pagination / Load More Section */}
                        <div className="mt-2 flex items-center justify-center py-4 pb-6">
                            {hasMore ? (
                                <button
                                    onClick={onLoadMoreButtonClick}
                                    disabled={isLoadingMore}
                                    className="flex items-center gap-2 rounded-full border border-gray-200 bg-white px-8 py-3 text-sm font-semibold text-gray-700 shadow-sm transition-all hover:border-orange-200 hover:bg-orange-50 hover:text-orange-600 disabled:cursor-not-allowed disabled:opacity-50"
                                >
                                    {isLoadingMore ? (
                                        <>
                                            <Loader2 className="h-4 w-4 animate-spin text-orange-500" />
                                            Loading more...
                                        </>
                                    ) : (
                                        "Load More Transactions"
                                    )}
                                </button>
                            ) : (
                                <div className="flex flex-col items-center gap-1 text-gray-400">
                                    <div className="h-px w-12 bg-gray-200" />
                                    <span className="text-xs font-medium tracking-wider uppercase">
                                        End of Activity
                                    </span>
                                </div>
                            )}
                        </div>
                    </>
                )}
            </div>
        </div>
    );
}

import {
    flexRender,
    getCoreRowModel,
    getSortedRowModel,
    useReactTable,
    createColumnHelper,
    SortingState,
    VisibilityState,
} from "@tanstack/react-table";

import { formatCurrency } from "@/lib/utils";
import { ActivityItem } from "./types";
import {
    ArrowDownLeft,
    ArrowUpRight,
    ArrowDown,
    ArrowUp,
    Settings2,
    Loader2,
    Search,
    Filter,
    X,
    Calendar,
    ChevronRight,
} from "lucide-react";
import { useState } from "react";

interface ActivityListProps {
    data: ActivityItem[];
    selectedItem: ActivityItem | null;
    onItemClick: (item: ActivityItem) => void;
    onLoadMoreButtonClick: () => void;
    hasMore: boolean;
    isLoadingMore: boolean;
    isFiltering: boolean;
    onApplyFilter: (start?: string, end?: string) => void;
    onClearFilter: () => void;
}

const columnHelper = createColumnHelper<ActivityItem>();

const columns = [
    columnHelper.display({
        id: "index",
        header: () => "No.#",
        size: 20,
        cell: (info) => (
            <div className="text-center text-xs font-medium text-gray-400">
                {info.row.index + 1}
            </div>
        ),
    }),
    columnHelper.accessor("date", {
        header: "Date",
        size: 100,
        cell: (info) => (
            <span className="text-xs text-gray-500">
                {new Date(info.getValue()).toLocaleDateString("en-US", {
                    month: "short",
                    day: "numeric",
                    year: "2-digit",
                })}
            </span>
        ),
    }),
    columnHelper.accessor("name", {
        header: "Details",
        size: 250,
        cell: (info) => {
            const item = info.row.original;
            return (
                <div className="flex items-center gap-3">
                    <div
                        className={`shrink-0 rounded-full p-1.5 ${item.isIncome ? "bg-green-100" : "bg-red-50"}`}
                    >
                        {item.isIncome ? (
                            <ArrowDownLeft className="h-3 w-3 text-green-600" />
                        ) : (
                            <ArrowUpRight className="h-3 w-3 text-red-600" />
                        )}
                    </div>
                    <div className="flex flex-col overflow-hidden">
                        <span className="truncate text-sm font-medium text-gray-900">
                            {info.getValue()}
                        </span>
                        <span className="text-xs text-gray-500">
                            {item.type}
                        </span>
                    </div>
                </div>
            );
        },
    }),
    columnHelper.accessor("currency", {
        header: "Currency",
        size: 100,
        cell: (info) => (
            <span className="text-sm text-gray-500">{info.getValue()}</span>
        ),
    }),
    columnHelper.accessor("groupName", {
        header: "Group",
        size: 140,
        cell: (info) => (
            <span className="text-sm text-gray-500">
                {info.getValue() || "-"}
            </span>
        ),
    }),
    columnHelper.accessor("hasReceipt", {
        header: "Receipt",
        size: 100,
        cell: (info) => (
            <span className="text-sm text-gray-500">
                {info.getValue() ? "Yes" : "No"}
            </span>
        ),
    }),
    columnHelper.accessor("splitCount", {
        header: "Split",
        size: 100,
        cell: (info) => (
            <span className="text-sm text-gray-500">
                {info.getValue() > 0 ? info.getValue() : "-"}
            </span>
        ),
    }),
    columnHelper.accessor("amount", {
        header: () => <div className="text-right">Amount</div>,
        size: 120,
        cell: (info) => {
            const item = info.row.original;
            return (
                <div
                    className={`text-right text-sm font-semibold ${item.isIncome ? "text-green-600" : "text-red-500"}`}
                >
                    {formatCurrency((item.isIncome ? 1 : -1) * info.getValue())}
                </div>
            );
        },
        sortingFn: (a, b) => {
            const amountA = a.original.amount * (a.original.isIncome ? 1 : -1);
            const amountB = b.original.amount * (b.original.isIncome ? 1 : -1);
            return amountA > amountB ? 1 : amountA < amountB ? -1 : 0;
        },
    }),
];

export function ActivityList({
    data,
    selectedItem,
    onItemClick,
    onLoadMoreButtonClick,
    hasMore,
    isLoadingMore,
    isFiltering,
    onApplyFilter,
    onClearFilter,
}: ActivityListProps) {
    const [isScrolled, setIsScrolled] = useState(false);
    const [sorting, setSorting] = useState<SortingState>([]);

    const [columnVisibility, setColumnVisibility] = useState<VisibilityState>({
        index: false,
        currency: false,
        hasReceipt: false,
        splitCount: false,
    });
    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [isResizingEnabled, setIsResizingEnabled] = useState(true);

    const [filterMode, setFilterMode] = useState<"none" | "month" | "range">(
        "none",
    );
    const [isEditing, setIsEditing] = useState(false);
    const [monthValue, setMonthValue] = useState("");
    const [startDate, setStartDate] = useState("");
    const [endDate, setEndDate] = useState("");

    const table = useReactTable({
        data,
        columns,
        state: {
            sorting,
            columnVisibility,
        },
        onSortingChange: setSorting,
        onColumnVisibilityChange: setColumnVisibility,
        getCoreRowModel: getCoreRowModel(),
        getSortedRowModel: getSortedRowModel(),
        columnResizeMode: "onChange",
    });

    const handleScroll = (e: React.UIEvent<HTMLDivElement>) => {
        setIsScrolled(e.currentTarget.scrollTop > 0);
    };

    const toggleResizing = (enabled: boolean) => {
        setIsResizingEnabled(enabled);
        if (!enabled) {
            table.resetColumnSizing();
        }
    };

    // --- NEW: Calculate dates before sending to parent ---
    function handleApply() {
        let calculatedStart: string | undefined = undefined;
        let calculatedEnd: string | undefined = undefined;

        if (filterMode === "month" && monthValue) {
            const [year, month] = monthValue.split("-");
            calculatedStart = new Date(
                parseInt(year),
                parseInt(month) - 1,
                1,
            ).toISOString();
            calculatedEnd = new Date(
                parseInt(year),
                parseInt(month),
                0,
                23,
                59,
                59,
                999,
            ).toISOString();
        } else if (filterMode === "range" && startDate && endDate) {
            calculatedStart = new Date(
                `${startDate}T00:00:00.000`,
            ).toISOString();
            calculatedEnd = new Date(`${endDate}T23:59:59.999`).toISOString();
        }

        setIsEditing(false);
        onApplyFilter(calculatedStart, calculatedEnd);
    }

    function handleClear() {
        setMonthValue("");
        setStartDate("");
        setEndDate("");
        setFilterMode("none");
        setIsEditing(false);
        onClearFilter();
    }

    return (
        <div className="flex h-full flex-col">
            {/* UNIFIED TOOLBAR */}
            <div className="flex shrink-0 items-center justify-between border-b border-gray-100 bg-white px-5 py-3">
                <div className="flex flex-1 items-center gap-2">
                    {filterMode === "none" ? (
                        <>
                            <button
                                onClick={() => {
                                    setFilterMode("month");
                                    setIsEditing(true);
                                }}
                                className="flex items-center gap-2 rounded-full border border-gray-200 bg-white px-4 py-1.5 text-sm font-medium text-gray-600 transition-all hover:border-orange-200 hover:bg-orange-50 hover:text-orange-600"
                            >
                                <Calendar className="h-4 w-4" />
                                Month
                            </button>
                            <button
                                onClick={() => {
                                    setFilterMode("range");
                                    setIsEditing(true);
                                }}
                                className="flex items-center gap-2 rounded-full border border-gray-200 bg-white px-4 py-1.5 text-sm font-medium text-gray-600 transition-all hover:border-orange-200 hover:bg-orange-50 hover:text-orange-600"
                            >
                                <Filter className="h-4 w-4" />
                                Date Range
                            </button>
                        </>
                    ) : filterMode === "month" ? (
                        isEditing || !isFiltering ? (
                            <div className="animate-in fade-in zoom-in-95 flex items-center gap-2 rounded-full border border-orange-200 bg-orange-50/30 p-1 pl-4 duration-200">
                                <span className="text-xs font-semibold tracking-wider text-orange-600 uppercase">
                                    Month
                                </span>
                                <input
                                    type="month"
                                    value={monthValue}
                                    onChange={(e) =>
                                        setMonthValue(e.target.value)
                                    }
                                    className="bg-transparent text-sm font-medium text-gray-900 [color-scheme:light] outline-none"
                                />
                                <div className="flex items-center gap-1 pl-2">
                                    <button
                                        onClick={handleApply}
                                        disabled={!monthValue}
                                        className="rounded-full bg-orange-600 px-3 py-1 text-xs font-bold text-white hover:bg-orange-700 disabled:opacity-50"
                                    >
                                        Apply
                                    </button>
                                    <button
                                        onClick={() => {
                                            if (!isFiltering)
                                                setFilterMode("none");
                                            setIsEditing(false);
                                        }}
                                        className="rounded-full p-1 text-gray-400 hover:bg-gray-100 hover:text-gray-600"
                                    >
                                        <X className="h-4 w-4" />
                                    </button>
                                </div>
                            </div>
                        ) : (
                            <button
                                onClick={() => setIsEditing(true)}
                                className="flex items-center gap-2 rounded-full border border-orange-200 bg-orange-50 px-4 py-1.5 text-sm font-semibold text-orange-700 transition-all hover:bg-orange-100"
                            >
                                <Calendar className="h-4 w-4" />
                                {new Date(
                                    monthValue + "-01",
                                ).toLocaleDateString("en-US", {
                                    month: "short",
                                    year: "numeric",
                                })}
                                <div
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        handleClear();
                                    }}
                                    className="ml-1 rounded-full p-0.5 hover:bg-orange-200"
                                >
                                    <X className="h-3.5 w-3.5" />
                                </div>
                            </button>
                        )
                    ) : isEditing || !isFiltering ? (
                        <div className="animate-in fade-in zoom-in-95 flex items-center gap-2 rounded-full border border-orange-200 bg-orange-50/30 p-1 pl-4 duration-200">
                            <span className="text-xs font-semibold tracking-wider text-orange-600 uppercase">
                                Range
                            </span>
                            <div className="flex items-center gap-2">
                                <input
                                    type="date"
                                    value={startDate}
                                    onChange={(e) =>
                                        setStartDate(e.target.value)
                                    }
                                    className="bg-transparent text-sm font-medium text-gray-900 [color-scheme:light] outline-none"
                                />
                                <ChevronRight className="h-3 w-3 text-gray-400" />
                                <input
                                    type="date"
                                    value={endDate}
                                    onChange={(e) => setEndDate(e.target.value)}
                                    className="bg-transparent text-sm font-medium text-gray-900 [color-scheme:light] outline-none"
                                />
                            </div>
                            <div className="flex items-center gap-1 pl-2">
                                <button
                                    onClick={handleApply}
                                    disabled={!startDate || !endDate}
                                    className="rounded-full bg-orange-600 px-3 py-1 text-xs font-bold text-white hover:bg-orange-700 disabled:opacity-50"
                                >
                                    Apply
                                </button>
                                <button
                                    onClick={() => {
                                        if (!isFiltering) setFilterMode("none");
                                        setIsEditing(false);
                                    }}
                                    className="rounded-full p-1 text-gray-400 hover:bg-gray-100 hover:text-gray-600"
                                >
                                    <X className="h-4 w-4" />
                                </button>
                            </div>
