import { getCurrentUser } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { notFound } from "next/navigation";
import Link from "next/link";
import { ArrowLeft } from "lucide-react";

import SegmentedBar from "./_components/SegmentedBar";

export default async function GroupDetailPage({
    params,
}: {
    params: Promise<{ id: string }>;
}) {
    const { id } = await params;
    const user = await getCurrentUser();
    if (!user) return null;

    const [group, groupTransactions] = await Promise.all([
        prisma.group.findUnique({
            where: { id },
            include: {
                members: {
                    include: { user: true },
                },
            },
        }),
        prisma.transaction.findMany({
            where: {
                groupId: id,
                deletedAt: null,
            },
            include: {
                category: true,
                group: true,
                splits: {
                    include: { user: true },
                },
                payer: true,
            },
        }),
    ]);

    if (!group) return notFound();

    // Security: Check if user is a member
    const isMember = group.members.some((m) => m.userId === user.id);
    if (!isMember) return notFound();

    return (
        <main className="flex h-full flex-1 flex-col p-6">
            <Link
                href="/groups"
                className="mb-6 flex items-center gap-2 text-sm font-medium text-gray-500 hover:text-gray-900"
            >
                <ArrowLeft className="h-4 w-4" />
                Back to Groups
            </Link>

            <h1 className="text-3xl font-bold text-gray-900">{group.name}</h1>
            <p className="mt-2 text-gray-500">
                Full dashboard for {group.name} is coming soon.
            </p>

            <div className="mt-12 rounded-2xl border-2 border-dashed border-gray-200 p-12 text-center">
                <p className="text-gray-400">
                    This page will eventually contain group-specific charts,
                    transaction history, and settlement tools.
                </p>
            </div>
        </main>
    );
}

