"use client";

import { CategoryStat } from "./types";
import { formatCurrency } from "@/lib/utils";
import { X } from "lucide-react";

interface InteractiveSegmentedBarProps {
    stats: CategoryStat[];
    selectedCategoryId: string | null;
    onSelectCategory: (id: string | null) => void;
    totalSpent: number;
}

export function InteractiveSegmentedBar({
    stats,
    selectedCategoryId,
    onSelectCategory,
    totalSpent,
}: InteractiveSegmentedBarProps) {
    if (totalSpent === 0) return null;

    return (
        <div className="w-full space-y-6">
            <div className="flex items-center justify-between">
                <h3 className="text-sm font-bold tracking-widest text-gray-400 uppercase">
                    Spending by Category
                </h3>
                {selectedCategoryId && (
                    <button
                        onClick={() => onSelectCategory(null)}
                        className="flex items-center gap-1.5 text-xs font-bold text-orange-600 hover:text-orange-700 transition-colors"
                    >
                        <X className="h-3.5 w-3.5" />
                        Clear Filter
                    </button>
                )}
            </div>

            {/* The Actual Bar */}
            <div className="relative flex h-10 w-full overflow-hidden rounded-2xl bg-gray-100 p-1 shadow-inner">
                {stats.map((stat, idx) => {
                    const isSelected = selectedCategoryId === stat.id;
                    const isAnySelected = selectedCategoryId !== null;

                    return (
                        <div
                            key={stat.id}
                            onClick={() => onSelectCategory(isSelected ? null : stat.id)}
                            className={`group relative h-full cursor-pointer transition-all duration-300 ease-out first:rounded-l-xl last:rounded-r-xl ${
                                isAnySelected && !isSelected ? "opacity-30 grayscale-[0.5] scale-[0.98]" : "opacity-100 scale-100"
                            }`}
                            style={{ 
                                width: `${stat.percentage}%`,
                                backgroundColor: stat.color,
                                marginLeft: idx === 0 ? 0 : "2px"
                            }}
                        >
                            {/* Hover Tooltip */}
                            <div className="absolute -top-12 left-1/2 z-20 -translate-x-1/2 scale-0 rounded-lg bg-gray-900 px-3 py-1.5 text-xs font-bold text-white shadow-xl transition-all group-hover:scale-100">
                                {stat.name}: {formatCurrency(stat.amount)}
                                <div className="absolute -bottom-1 left-1/2 h-2 w-2 -translate-x-1/2 rotate-45 bg-gray-900" />
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* Legend */}
            <div className="flex flex-wrap gap-4">
                {stats.map((stat) => {
                    const isSelected = selectedCategoryId === stat.id;
                    return (
                        <button
                            key={stat.id}
                            onClick={() => onSelectCategory(isSelected ? null : stat.id)}
                            className={`flex items-center gap-2 rounded-full border px-4 py-2 transition-all duration-200 ${
                                isSelected 
                                    ? "border-gray-900 bg-gray-900 text-white shadow-md" 
                                    : "border-gray-200 bg-white text-gray-600 hover:border-gray-300 hover:bg-gray-50"
                            }`}
                        >
                            <span 
                                className="h-3 w-3 rounded-full" 
                                style={{ backgroundColor: isSelected ? "#fff" : stat.color }}
                            />
                            <span className="text-xs font-bold leading-none">
                                {stat.icon} {stat.name}
                            </span>
                            <span className={`text-[10px] font-medium opacity-60 ${isSelected ? "text-white" : "text-gray-400"}`}>
                                {Math.round(stat.percentage)}%
                            </span>
                        </button>
                    );
                })}
            </div>
        </div>
    );
}

