"use client";

import { useState, useMemo } from "react";
import { GroupTransaction, MemberStanding, CategoryStat } from "./types";
import { InteractiveSegmentedBar } from "./InteractiveSegmentedBar";
import { MemberStandings } from "./MemberStandings";
import { GroupTransactionsTable } from "./GroupTransactionsTable";
import { formatCurrency } from "@/lib/utils";
import { Wallet, Users as UsersIcon, Receipt as ReceiptIcon } from "lucide-react";

interface GroupDashboardClientProps {
    transactions: GroupTransaction[];
    totalSpent: number;
    memberStandings: MemberStanding[];
    currency: string;
}

export function GroupDashboardClient({
    transactions,
    totalSpent,
    memberStandings,
    currency,
}: GroupDashboardClientProps) {
    const [selectedCategoryId, setSelectedCategoryId] = useState<string | null>(null);

    // 1. Calculate Category Stats for the Segmented Bar
    const categoryStats = useMemo(() => {
        const statsMap = new Map<string, { id: string; name: string; icon: string | null; amount: number }>();

        transactions.forEach((txn) => {
            const catId = txn.category?.id || "uncategorized";
            const current = statsMap.get(catId) || { 
                id: catId, 
                name: txn.category?.name || "Uncategorized", 
                icon: txn.category?.icon || "📄", 
                amount: 0 
            };
            current.amount += txn.amount;
            statsMap.set(catId, current);
        });

        // Colors for the bar segments
        const colors = [
            "#f97316", // orange-500
            "#3b82f6", // blue-500
            "#10b981", // emerald-500
            "#8b5cf6", // violet-500
            "#ec4899", // pink-500
            "#06b6d4", // cyan-500
            "#eab308", // yellow-500
            "#6366f1", // indigo-500
        ];

        return Array.from(statsMap.values())
            .map((stat, idx) => ({
                ...stat,
                percentage: totalSpent > 0 ? (stat.amount / totalSpent) * 100 : 0,
                color: colors[idx % colors.length]
            }))
            .sort((a, b) => b.amount - a.amount);
    }, [transactions, totalSpent]);

    // 2. Filter transactions based on selection
    const filteredTransactions = useMemo(() => {
        if (!selectedCategoryId) return transactions;
        return transactions.filter(t => (t.category?.id || "uncategorized") === selectedCategoryId);
    }, [transactions, selectedCategoryId]);

    return (
        <div className="flex flex-col gap-12 pb-20">
            {/* High-Level Overview Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="rounded-3xl border border-gray-100 bg-white p-8 shadow-sm transition-all hover:shadow-md">
                    <div className="flex items-center gap-3 text-sm font-bold tracking-widest text-gray-400 uppercase mb-4">
                        <Wallet className="h-4 w-4 text-orange-500" />
                        Total Spent
                    </div>
                    <div className="text-4xl font-black tracking-tighter text-gray-900">
                        {formatCurrency(totalSpent)}
                    </div>
                    <p className="mt-2 text-xs font-medium text-gray-500 italic">Across all categories in this group</p>
                </div>

                <div className="rounded-3xl border border-gray-100 bg-white p-8 shadow-sm transition-all hover:shadow-md">
                    <div className="flex items-center gap-3 text-sm font-bold tracking-widest text-gray-400 uppercase mb-4">
                        <UsersIcon className="h-4 w-4 text-blue-500" />
                        Member Share
                    </div>
                    <div className="text-4xl font-black tracking-tighter text-gray-900">
                        {formatCurrency(totalSpent / memberStandings.length)}
                    </div>
                    <p className="mt-2 text-xs font-medium text-gray-500 italic text-balance">Average per member split</p>
                </div>

                <div className="rounded-3xl border border-gray-100 bg-white p-8 shadow-sm transition-all hover:shadow-md">
                    <div className="flex items-center gap-3 text-sm font-bold tracking-widest text-gray-400 uppercase mb-4">
                        <ReceiptIcon className="h-4 w-4 text-emerald-500" />
                        Activities
                    </div>
                    <div className="text-4xl font-black tracking-tighter text-gray-900">
                        {transactions.length}
                    </div>
                    <p className="mt-2 text-xs font-medium text-gray-500 italic">Total recorded events</p>
                </div>
            </div>

            {/* Member Standings Section */}
            <MemberStandings standings={memberStandings} />

            {/* Interactive Spending Bar Chart */}
            <InteractiveSegmentedBar 
                stats={categoryStats} 
                selectedCategoryId={selectedCategoryId} 
                onSelectCategory={setSelectedCategoryId}
                totalSpent={totalSpent}
            />

            {/* Simplified Activity Table */}
            <GroupTransactionsTable data={filteredTransactions} />
        </div>
    );
}

