import { getCurrentUser } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { notFound } from "next/navigation";
import Link from "next/link";
import { ArrowLeft, Users, Receipt } from "lucide-react";
import { GroupDashboardClient } from "./_components/GroupDashboardClient";

export default async function GroupDetailPage({
    params,
}: {
    params: Promise<{ id: string }>;
}) {
    const { id } = await params;
    const user = await getCurrentUser();
    if (!user) return null;

    // 1. Fetch the group, its members, and all transactions (including category details)
    const group = await prisma.group.findUnique({
        where: { id },
        include: {
            members: {
                include: { user: true },
            },
            transactions: {
                where: { deletedAt: null },
                include: {
                    category: true,
                    payer: true,
                    splits: {
                        include: { user: true },
                    },
                },
                orderBy: { date: "desc" },
            },
        },
    });

    if (!group) return notFound();

    // Security check: must be a member
    const isMember = group.members.some((m) => m.userId === user.id);
    if (!isMember) return notFound();

    // 2. Map data for the client component
    const totalSpent = group.transactions.reduce(
        (sum, txn) => sum + txn.amount.toNumber(),
        0,
    );

    const clientTransactions = group.transactions.map((txn) => ({
        id: txn.id,
        description: txn.description,
        amount: txn.amount.toNumber(),
        date: txn.date.toISOString(),
        currency: txn.currency,
        category: txn.category
            ? {
                  id: txn.category.id,
                  name: txn.category.name,
                  icon: txn.category.icon,
              }
            : null,
        payer: {
            id: txn.payer.id,
            name: txn.payer.name || "Unknown",
        },
        splitCount: txn.splits.length,
        splits: txn.splits.map((s) => ({
            userId: s.userId,
            userName: s.user.name || "Unknown",
            amount: s.amount.toNumber(),
        })),
    }));

    // 3. Calculate Member Standings (Who owes whom in this group)
    // We'll calculate: (Sum of Splits Owed) - (Sum of Expenses Paid)
    // Actually simpler: For each member, their balance = (Amount they PAID for the group) - (Amount they are OWED as a split)
    const memberStandings = group.members
        .map((member) => {
            const amountPaid = group.transactions
                .filter((t) => t.payerId === member.userId)
                .reduce((sum, t) => sum + t.amount.toNumber(), 0);

            const amountOwedFromSplits = group.transactions.reduce(
                (sum, txn) => {
                    const mySplit = txn.splits.find(
                        (s) => s.userId === member.userId,
                    );
                    return sum + (mySplit ? mySplit.amount.toNumber() : 0);
                },
                0,
            );

            return {
                userId: member.userId,
                userName: member.user.name || "Unknown",
                role: member.role,
                netBalance: amountPaid - amountOwedFromSplits,
            };
        })
        .sort((a, b) => b.netBalance - a.netBalance);

    return (
        <main className="flex h-full flex-1 flex-col p-6">
            {/* Header */}
            <div className="mb-8">
                <Link
                    href="/groups"
                    className="mb-4 flex items-center gap-2 text-sm font-medium text-gray-500 transition-colors hover:text-orange-600"
                >
                    <ArrowLeft className="h-4 w-4" />
                    Back to Groups
                </Link>
                <div className="flex items-end justify-between">
                    <div>
                        <h1 className="text-4xl font-black tracking-tighter text-gray-900">
                            {group.name}
                        </h1>
                        <div className="mt-2 flex items-center gap-4 text-sm font-medium text-gray-500">
                            <div className="flex items-center gap-1.5">
                                <Users className="h-4 w-4 text-gray-400" />
                                {group.members.length} Members
                            </div>
                            <div className="flex items-center gap-1.5">
                                <Receipt className="h-4 w-4 text-gray-400" />
                                {group.transactions.length} Transactions
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Dashboard Client Area */}
            <GroupDashboardClient
                transactions={clientTransactions}
                totalSpent={totalSpent}
                memberStandings={memberStandings}
                currency={group.currency}
            />
        </main>
    );
}

